// DesignConfig 레터링·폰트·색상·섹션 구성
type DesignConfig struct {
	// Canvas 그림판 섹션 — 자유 배치 그리기·텍스트·이미지 요소 (jsonb passthrough). type·tool은 enum 충돌 회피 위해 string
	Canvas *struct {
		BackgroundColor *string `json:"background_color,omitempty"`
		Items           *[]struct {
			Color      *string  `json:"color,omitempty"`
			FontFamily *string  `json:"font_family,omitempty"`
			FontSize   *float32 `json:"font_size,omitempty"`
			Height     *float32 `json:"height,omitempty"`
			Id         *string  `json:"id,omitempty"`
			ImageUrl   *string  `json:"image_url,omitempty"`
			IsSticker  *bool    `json:"is_sticker,omitempty"`
			Rotation   *float32 `json:"rotation,omitempty"`

			// Strokes type=drawing 일 때의 획 배열
			Strokes *[]struct {
				Color *string `json:"color,omitempty"`
				D     *string `json:"d,omitempty"`

				// Tool 획 도구: pen | brush
				Tool  *string  `json:"tool,omitempty"`
				Width *float32 `json:"width,omitempty"`
			} `json:"strokes,omitempty"`
			Text *string `json:"text,omitempty"`

			// Type 요소 종류: drawing | text | image
			Type *string `json:"type,omitempty"`

			// ViewBox type=drawing 일 때의 좌표계
			ViewBox *struct {
				Height *float32 `json:"height,omitempty"`
				Width  *float32 `json:"width,omitempty"`
			} `json:"view_box,omitempty"`
			Width  *float32 `json:"width,omitempty"`
			X      *float32 `json:"x,omitempty"`
			Y      *float32 `json:"y,omitempty"`
			ZIndex *int     `json:"z_index,omitempty"`
		} `json:"items,omitempty"`

		// Subtitle 그림판 섹션 부제목(영문)
		Subtitle *string `json:"subtitle,omitempty"`

		// Title 그림판 섹션 제목(한글). 다른 섹션 헤더와 동일 스타일로 표시
		Title   *string `json:"title,omitempty"`
		ViewBox *struct {
			Height *float32 `json:"height,omitempty"`
			Width  *float32 `json:"width,omitempty"`
		} `json:"view_box,omitempty"`
	} `json:"canvas,omitempty"`

	// CoverImagePosition 커버 이미지 위치·확대 조정 (react-easy-crop 결과)
	CoverImagePosition *struct {
		CropArea *struct {
			Height *float32 `json:"height,omitempty"`
			Width  *float32 `json:"width,omitempty"`
			X      *float32 `json:"x,omitempty"`
			Y      *float32 `json:"y,omitempty"`
		} `json:"cropArea,omitempty"`
		EditorCrop *struct {
			X *float32 `json:"x,omitempty"`
			Y *float32 `json:"y,omitempty"`
		} `json:"editorCrop,omitempty"`
		Zoom *float32 `json:"zoom,omitempty"`
	} `json:"cover_image_position,omitempty"`
	Lettering *struct {
		Animation   *DesignConfigLetteringAnimation `json:"animation,omitempty"`
		DrawViewBox *struct {
			Height *float32 `json:"height,omitempty"`
			Width  *float32 `json:"width,omitempty"`
		} `json:"draw_view_box,omitempty"`
		Height   *float32                     `json:"height,omitempty"`
		ImageUrl *string                      `json:"image_url,omitempty"`
		Rotation *float32                     `json:"rotation,omitempty"`
		Source   *DesignConfigLetteringSource `json:"source,omitempty"`
		Strokes  *[]struct {
			Color *string `json:"color,omitempty"`
			D     *string `json:"d,omitempty"`

			// Points 획 재생용 타임드 좌표 (x,y,t=획 시작 기준 ms). 없으면 재생 대신 fade
			Points *[]struct {
				T *float32 `json:"t,omitempty"`
				X *float32 `json:"x,omitempty"`
				Y *float32 `json:"y,omitempty"`
			} `json:"points,omitempty"`

			// Tool 획 도구 (미설정 시 pen)
			Tool  *DesignConfigLetteringStrokesTool `json:"tool,omitempty"`
			Width *float32                          `json:"width,omitempty"`
		} `json:"strokes,omitempty"`
		Width *float32 `json:"width,omitempty"`
		X     *float32 `json:"x,omitempty"`
		Y     *float32 `json:"y,omitempty"`
	} `json:"lettering,omitempty"`
	Sections *[]struct {
		Enabled bool                    `json:"enabled"`
		Key     DesignConfigSectionsKey `json:"key"`
		Order   int                     `json:"order"`
	} `json:"sections,omitempty"`
	Theme *struct {
		Colors *struct {
			Accent     *string `json:"accent,omitempty"`
			Background *string `json:"background,omitempty"`
			Button     *string `json:"button,omitempty"`
			Text       *string `json:"text,omitempty"`
		} `json:"colors,omitempty"`
		Fonts *struct {
			Body     *string `json:"body,omitempty"`
			Subtitle *string `json:"subtitle,omitempty"`
			Title    *string `json:"title,omitempty"`
		} `json:"fonts,omitempty"`
	} `json:"theme,omitempty"`
}

